def __init__(self):
    self.arg_map = {}
    self.var_map = {}
    self.arg_count = 0
    self.var_count = 0

def visit_Name(self, node):
    if isinstance(node.ctx, (ast.Store, ast.Load)):
        if node.id in self.arg_map:
            node.id = self.arg_map[node.id]
        elif node.id in _BUILTIN_NAMES:
            pass  # preserve builtins (print, len, range, etc.)
        elif node.id not in self.var_map:
            name = f"var{self.var_count}"
            self.var_map[node.id] = name
            self.var_count += 1
            node.id = name
        else:
            node.id = self.var_map[node.id]
    return node

def visit_arg(self, node):
    if node.arg in self.arg_map:
        node.arg = self.arg_map[node.arg]
    return node

def _walk_definitions(node: ast.AST):
    """Yield top-level and class-method function/class defs, skipping nested functions."""
    for child in ast.iter_child_nodes(node):
        if isinstance(child, (ast.FunctionDef, ast.AsyncFunctionDef)):
            yield child
        elif isinstance(child, ast.ClassDef):
            yield child
            yield from _walk_definitions(child)
        else:
            yield from _walk_definitions(child)

def extract_functions_from_file(fpath: Path, root: Path) -> Tuple[
        List[FunctionRecord], List[ClassRecord], Optional[str]]:
    """Parse one file and extract all functions and classes."""
    try:
        source = fpath.read_text(encoding="utf-8", errors="ignore")
    except Exception as e:
        return [], [], str(e)

    try:
        tree = ast.parse(source, filename=str(fpath))
    except SyntaxError as e:
        return [], [], f"SyntaxError: {e}"

    rel_path = str(fpath.relative_to(root)).replace("\\", "/")
    lines = source.splitlines()
    functions = []
    classes = []

    for node in _walk_definitions(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            func_record = _build_function_record(node, rel_path, source, lines)
            functions.append(func_record)
        elif isinstance(node, ast.ClassDef):
            class_record = _build_class_record(node, rel_path)
            classes.append(class_record)

    return functions, classes, None

def _should_prune_dir(dirname: str, rel_dir: str, exclude: list) -> bool:
    """Return True if *dirname* should be pruned from the file walk."""
    if dirname in _ALWAYS_SKIP or dirname.endswith(".egg-info"):
        return True
    if exclude:
        qualified = os.path.join(rel_dir, dirname) if rel_dir != "." else dirname
        return any(qualified.startswith(p) for p in exclude)
    return False

def _matches_include_filter(rel_dir: str, include: list) -> bool:
    """Return True if *rel_dir* passes the include filter (or no filter set)."""
    if not include:
        return True
    top = rel_dir.split(os.sep)[0] if rel_dir != "." else "."
    if top == ".":
        return True
    return any(top.startswith(p) for p in include)

def collect_py_files(root: Path, exclude: List[str] = None,
                     include: List[str] = None) -> List[Path]:
    """Walk root and return .py files respecting include/exclude rules."""
    exclude = exclude or []
    include = include or []
    results = []
    try:
        walker = os.walk(root)
    except PermissionError:
        logger.warning(f"Permission denied: {root}")
        return results
    for dirpath, dirnames, filenames in walker:
        rel_dir = os.path.relpath(dirpath, root)
        dirnames[:] = [d for d in dirnames
                       if not _should_prune_dir(d, rel_dir, exclude)]
        if not _matches_include_filter(rel_dir, include):
            continue
        for fn in filenames:
            if fn.endswith(".py") and fn not in _ALWAYS_SKIP_FILES:
                results.append(Path(dirpath) / fn)
    return results

def to_dict(self) -> Dict[str, Any]:
    return {
        "os": self.os_name,
        "arch": self.arch,
        "processor": self.processor,
        "rust_target": self.rust_target,
        "cpu_features": self.cpu_features,
    }

def _detect_x86_features() -> List[str]:
    """Best-effort CPU feature detection for x86_64."""
    detected: List[str] = []
    system = platform.system()

    if system == "Windows":
        # Check via environment or WMIC
        try:
            # Registry approach via Python
            import winreg
            key = winreg.OpenKey(
                winreg.HKEY_LOCAL_MACHINE,
                r"HARDWARE\DESCRIPTION\System\CentralProcessor\0")
            ident, _ = winreg.QueryValueEx(key, "Identifier")
            # All modern Intel/AMD support SSE4.2
            detected.append("sse4.2")
            detected.append("popcnt")
            # Family 6 model >= 60 likely has AVX2
            m = re.search(r"Model\s+(\d+)", ident)
            if m and int(m.group(1)) >= 60:
                detected.extend(["avx2", "bmi2"])
        except Exception:
            detected = ["sse4.2"]
    elif system == "Linux":
        try:
            cpuinfo = Path("/proc/cpuinfo").read_text()
            flags_line = [line for line in cpuinfo.split("\n")
                          if line.startswith("flags")]
            if flags_line:
                flags = flags_line[0].split(":")[-1]
                for feat in _X86_FEATURES:
                    if feat in flags:
                        detected.append(feat)
        except Exception:
            pass
    elif system == "Darwin":
        try:
            out = subprocess.check_output(
                ["sysctl", "-a"], text=True, timeout=10)
            if "hw.optional.avx2_0: 1" in out:
                detected.append("avx2")
            detected.extend(["sse4.2", "popcnt"])
        except Exception:
            detected = ["sse4.2"]

    return detected

def _rust_op(op) -> str:
    """AST operator → Rust symbol."""
    return {
        ast.Add: "+", ast.Sub: "-", ast.Mult: "*", ast.Div: "/",
        ast.Mod: "%", ast.Pow: ".pow", ast.BitOr: "|", ast.BitAnd: "&",
        ast.BitXor: "^", ast.LShift: "<<", ast.RShift: ">>",
        ast.FloorDiv: "/",
    }.get(type(op), "+")

def _translate_body(stmts: list, indent: int = 1, *,
                    wrap_ok: bool = True,
                    ret_type: str = "") -> List[str]:
    """AST → Rust body translation (best-effort).

    Parameters
    ----------
    wrap_ok : bool
        If True, wrap return values in ``Ok(...)`` (PyO3 mode).
        If False, use plain ``return ...`` (binary mode).
    ret_type : str
        The Rust return type (e.g. "String", "f64") to guide coercions.
    """
    pad = "    " * indent
    lines: List[str] = []
    for stmt in stmts:
        if isinstance(stmt, ast.Return):
            if stmt.value:
                val = _rustify_expr(ast.unparse(stmt.value))
                # Coerce string literals → .to_string() when return is String
                needs_to_string = ("String" in ret_type) and re.match(r'^"[^"]*"$', val)
                if needs_to_string:
                    val = f'{val}.to_string()'
                if wrap_ok:
                    lines.append(f"{pad}Ok({val})")
                else:
                    lines.append(f"{pad}return {val};")
            else:
                if wrap_ok:
                    lines.append(f"{pad}Ok(())")
                else:
                    lines.append(f"{pad}return;")
        elif isinstance(stmt, ast.If):
            test = _rustify_expr(ast.unparse(stmt.test))
            lines.append(f"{pad}if {test} {{")
            lines.extend(_translate_body(stmt.body, indent + 1, wrap_ok=wrap_ok, ret_type=ret_type))
            if stmt.orelse:
                if len(stmt.orelse) == 1 and isinstance(stmt.orelse[0], ast.If):
                    lines.append(f"{pad}}} else ")
                    inner = _translate_body(stmt.orelse, indent, wrap_ok=wrap_ok, ret_type=ret_type)
                    if inner:
                        inner[0] = inner[0].lstrip()
                        lines[-1] += inner[0]
                        lines.extend(inner[1:])
                else:
                    lines.append(f"{pad}}} else {{")
                    lines.extend(_translate_body(stmt.orelse, indent + 1, wrap_ok=wrap_ok, ret_type=ret_type))
                    lines.append(f"{pad}}}")
            else:
                lines.append(f"{pad}}}")
        elif isinstance(stmt, ast.For):
            target = ast.unparse(stmt.target)
            iter_expr = _rustify_expr(ast.unparse(stmt.iter))
            lines.append(f"{pad}for {target} in {iter_expr} {{")
            lines.extend(_translate_body(stmt.body, indent + 1, wrap_ok=wrap_ok, ret_type=ret_type))
            lines.append(f"{pad}}}")
        elif isinstance(stmt, ast.While):
            test = _rustify_expr(ast.unparse(stmt.test))
            lines.append(f"{pad}while {test} {{")
            lines.extend(_translate_body(stmt.body, indent + 1, wrap_ok=wrap_ok, ret_type=ret_type))
            lines.append(f"{pad}}}")
        elif isinstance(stmt, ast.Assign):
            targets = _rustify_expr(ast.unparse(stmt.targets[0]))
            value = _rustify_expr(ast.unparse(stmt.value))
            lines.append(f"{pad}let mut {targets} = {value};")
        elif isinstance(stmt, ast.AugAssign):
            target = _rustify_expr(ast.unparse(stmt.target))
            op = _rust_op(stmt.op)
            value = _rustify_expr(ast.unparse(stmt.value))
            lines.append(f"{pad}{target} {op}= {value};")
        elif isinstance(stmt, ast.FunctionDef) or isinstance(stmt, ast.AsyncFunctionDef):
            # Nested function definitions → comment out
            lines.append(f"{pad}// TODO: nested fn {stmt.name}()")
        elif isinstance(stmt, ast.ClassDef):
            lines.append(f"{pad}// TODO: nested class {stmt.name}")
        elif isinstance(stmt, ast.Expr):
            expr_str = _rustify_expr(ast.unparse(stmt.value))
            # Skip docstrings
            if isinstance(stmt.value, ast.Constant) and isinstance(stmt.value.value, str):
                continue
            lines.append(f"{pad}{expr_str};")
        elif isinstance(stmt, ast.Pass):
            lines.append(f"{pad}// pass")
        elif isinstance(stmt, ast.Break):
            lines.append(f"{pad}break;")
        elif isinstance(stmt, ast.Continue):
            lines.append(f"{pad}continue;")
        elif isinstance(stmt, ast.Assert):
            test_expr = _rustify_expr(ast.unparse(stmt.test))
            lines.append(f"{pad}assert!({test_expr});")
        elif isinstance(stmt, ast.Try):
            lines.append(f"{pad}// try {{")
            lines.extend(_translate_body(stmt.body, indent + 1, wrap_ok=wrap_ok, ret_type=ret_type))
            for handler in stmt.handlers:
                exc_name = handler.type and ast.unparse(handler.type) or "Exception"
                lines.append(f"{pad}// }} catch {exc_name} {{")
                lines.extend(_translate_body(handler.body, indent + 1, wrap_ok=wrap_ok, ret_type=ret_type))
            lines.append(f"{pad}// }}")
        elif isinstance(stmt, ast.With):
            items = ", ".join(ast.unparse(i) for i in stmt.items)
            lines.append(f"{pad}// with {items} {{")
            lines.extend(_translate_body(stmt.body, indent + 1, wrap_ok=wrap_ok, ret_type=ret_type))
            lines.append(f"{pad}// }}")
        elif isinstance(stmt, ast.Raise):
            if stmt.exc:
                exc = _rustify_expr(ast.unparse(stmt.exc))
                # Escape inner quotes for panic!/Err strings
                exc_escaped = exc.replace('"', '\\"')
                if wrap_ok:
                    lines.append(f'{pad}return Err(PyErr::new::<pyo3::exceptions::PyRuntimeError, _>("{exc_escaped}"));')
                else:
                    lines.append(f'{pad}panic!("{exc_escaped}");')
            else:
                if wrap_ok:
                    lines.append(f"{pad}return Err(PyErr::new::<pyo3::exceptions::PyRuntimeError, _>(\"raised\"));")
                else:
                    lines.append(f'{pad}panic!("raised");')
        else:
            try:
                py_line = ast.unparse(stmt).split("\n")[0]
            except Exception:
                py_line = "..."
            lines.append(f"{pad}// TODO: {py_line}")
    return lines

def transpile_class(class_def: ast.ClassDef, *, pyfunction: bool = True) -> str:
    """Generate Rust struct and impl from a Python class."""
    lines: List[str] = []
    class_name = class_def.name

    # 1. Struct definition
    # Iterate over __init__ or __annotations__ to find fields
    fields: Dict[str, str] = {}

    # Check for __init__ to find fields
    init_method = None
    for item in class_def.body:
        if isinstance(item, ast.FunctionDef) and item.name == "__init__":
            init_method = item
            break

    if init_method:
        for stmt in init_method.body:
            if isinstance(stmt, ast.Assign):
                # self.x = y
                for target in stmt.targets:
                    if isinstance(target, ast.Attribute) and isinstance(target.value, ast.Name) and target.value.id == "self":
                        field_name = target.attr
                        # Infer type? Hard without annotations. Default to PyObject/String?
                        fields[field_name] = "PyObject" # Default

    # Check for type annotations in class body (Dataclasses)
    for item in class_def.body:
        if isinstance(item, ast.AnnAssign) and isinstance(item.target, ast.Name):
            fname = item.target.id
            ftype = "PyObject"
            if item.annotation:
                ftype = py_type_to_rust(ast.unparse(item.annotation))
            fields[fname] = ftype

    # Generate Struct
    if pyfunction:
        lines.append("#[pyclass]")
    lines.append(f"struct {class_name} {{")
    for fname, ftype in fields.items():
        lines.append(f"    {fname}: {ftype},")
    lines.append("}")
    lines.append("")

    # Generate Impl
    if pyfunction:
        lines.append("#[pymethods]")
    lines.append(f"impl {class_name} {{")

    # Generate __init__ as new()
    if init_method:
        lines.append("    #[new]")
        # TODO: parse init args
        args = []
        for arg in init_method.args.args:
            if arg.arg == "self":
                continue
            # Basic type inference
            atype = "PyObject"
            if arg.annotation:
                atype = py_type_to_rust(ast.unparse(arg.annotation))
            args.append(f"{arg.arg}: {atype}")
        args_str = ", ".join(args)

        lines.append(f"    fn new({args_str}) -> Self {{")
        lines.append(f"        {class_name} {{")
        # Initialize fields
        for fname in fields:
            # Check if arg matches field
            if fname in [a.split(":")[0] for a in args]:
                lines.append(f"            {fname},")
            else:
                lines.append(f"            {fname}: PyObject::default(), // TODO: default??")
        lines.append("        }")
        lines.append("    }")

    # Generate other methods
    for item in class_def.body:
        if isinstance(item, ast.FunctionDef):
            if item.name == "__init__":
                continue
            # Transpile method
            # Need to handle 'self' arg = &self
            # We reuse transpile_function logic but adapted for methods?
            # For now, just a simplified version
            lines.append(f"    // Method {item.name}")
            # ... (Full method transpilation logic would go here)
            # This is a scratchpad implementation.

    lines.append("}")
    return "\n".join(lines)

def transpile_function_ast(func_def: ast.FunctionDef | ast.AsyncFunctionDef, *, 
                          pyfunction: bool = True) -> str:
    """Generate Rust function from AST node."""
    lines: List[str] = []

    # Return type
    ret_rust = "PyObject"
    if func_def.returns:
        ret_rust = py_type_to_rust(ast.unparse(func_def.returns))

    if pyfunction:
        if not ret_rust.startswith("PyResult"):
            ret_rust = f"PyResult<{ret_rust}>"
    else:
         if ret_rust == "PyObject":
            ret_rust = "()"

    # Attributes
    if pyfunction:
        lines.append("#[pyfunction]")

    # Signature
    fn_name = func_def.name

    params = []
    for arg in func_def.args.args:
        if arg.arg == "self":
            continue
        ptype = "PyObject"
        if arg.annotation:
            ptype = py_type_to_rust(ast.unparse(arg.annotation))

        if not pyfunction and ptype == "PyObject":
            ptype = "String" # Binary mode fallback

        params.append(f"{arg.arg}: {ptype}")

    params_str = ", ".join(params)
    lines.append(f"fn {fn_name}({params_str}) -> {ret_rust} {{")

    # Body
    body_lines = _translate_body(func_def.body, indent=1, wrap_ok=pyfunction, ret_type=ret_rust)
    lines.extend(body_lines)

    if pyfunction:
         if body_lines and not any("Ok(" in ln for ln in body_lines[-3:]):
            lines.append("    Ok(())")

    lines.append("}")
    return "\n".join(lines)

def transpile_module(code: str, *, pyo3: bool = True) -> str:
    """Transpile an entire Python module to Rust."""
    try:
        tree = ast.parse(code)
    except Exception:
        return "// Parse error"

    lines = []
    lines.append("// Auto-transpiled module")
    lines.append("use pyo3::prelude::*;")
    lines.append("use std::collections::{HashMap, HashSet};")
    lines.append("")

    for node in tree.body:
        if isinstance(node, ast.ClassDef):
            lines.append(transpile_class(node, pyfunction=pyo3))
            lines.append("")
        elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            lines.append(transpile_function_ast(node, pyfunction=pyo3))
            lines.append("")
        elif isinstance(node, (ast.Import, ast.ImportFrom)):
            lines.append(f"// {ast.unparse(node)}")
        else:
             # Top-level code? Put in a comment or try to transpile (rare for library modules)
             pass 

    if pyo3:
        # Generate module init
        lines.append("")
        lines.append("#[pymodule]")
        lines.append("fn rust_module672(_py: Python, m: &Bound<'_, PyModule>) -> PyResult<()> {")
        for node in tree.body:
             if isinstance(node, ast.ClassDef):
                 lines.append(f"    m.add_class::<{node.name}>()?;")
             elif isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                 lines.append(f"    m.add_function(wrap_pyfunction!({node.name}, m)?)?;")
        lines.append("    Ok(())")
        lines.append("}")

    return "\n".join(lines)

def transpile_function(func: FunctionRecord, *,
                       pyfunction: bool = True) -> str:
    """Generate a full Rust function from a Python FunctionRecord.

    Parameters
    ----------
    func : FunctionRecord
        The parsed Python function to transpile.
    pyfunction : bool
        If True, add ``#[pyfunction]`` attribute for PyO3.
        If False, generate a plain Rust function (no PyResult wrapping).
    """
    lines: List[str] = []

    # 1. Return type
    ret_rust = py_type_to_rust(func.return_type or "")
    if pyfunction:
        if not ret_rust.startswith("PyResult"):
            ret_rust = f"PyResult<{ret_rust}>"
    else:
        # Binary mode — use plain Rust types
        if ret_rust == "PyObject":
            ret_rust = "()"

    # 2. Parameters
    rust_params: List[str] = []
    try:
        tree = ast.parse(func.code)
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                for arg in node.args.args:
                    name = arg.arg
                    if name == "self":
                        continue
                    if arg.annotation:
                        ann = ast.unparse(arg.annotation)
                        rtype = py_type_to_rust(ann)
                    else:
                        rtype = "String" if not pyfunction else "PyObject"
                    if not pyfunction and rtype == "PyObject":
                        rtype = "String"  # fallback for binary mode
                    rust_params.append(f"{name}: {rtype}")
                break
    except Exception:
        for p in func.parameters:
            if p != "self":
                rust_params.append(f"{p}: PyObject")

    params_str = ", ".join(rust_params)

    # 3. Signature
    if pyfunction:
        lines.append("#[pyfunction]")
    fn_name = func.name
    # Rust naming convention: snake_case (Python already uses it usually)
    lines.append(f"fn {fn_name}({params_str}) -> {ret_rust} {{")

    # 4. Body
    try:
        tree = ast.parse(func.code)
        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                body_lines = _translate_body(node.body, indent=1,
                                             wrap_ok=pyfunction,
                                             ret_type=ret_rust)
                lines.extend(body_lines)
                # If last line doesn't return, add appropriate return
                if pyfunction:
                    if body_lines and not any("Ok(" in ln for ln in body_lines[-3:]):
                        lines.append("    Ok(())")
                break
    except Exception:
        lines.append("    // TODO: translate function body")
        lines.append("    todo!()")

    lines.append("}")
    return "\n".join(lines)

def _parse_error_functions(stderr: str) -> List[str]:
    """Extract function names that caused compilation errors."""
    # Rust errors reference line numbers; we find which `fn xxx(` is near
    bad_lines: set = set()
    for m in re.finditer(r'-->\s*src[\\/]\w+\.rs:(\d+)', stderr):
        bad_lines.add(int(m.group(1)))
    return list(bad_lines)

def _find_artefact(project_dir: Path, target: str, *,
                   mode: str = "pyo3") -> str:
    """Locate the compiled artefact after a successful build."""
    release_dir = project_dir / "target"
    if target:
        release_dir = release_dir / target
    release_dir = release_dir / "release"

    if not release_dir.exists():
        return ""

    # Look for the right extension
    system = platform.system()
    if mode == "binary":
        ext = ".exe" if system == "Windows" else ""
        for f in release_dir.iterdir():
            if f.is_file() and f.suffix == ext and not f.name.startswith("."):
                if f.name.endswith(".d") or f.name.endswith(".exp"):
                    continue
                return str(f)
    else:
        # PyO3 cdylib
        if system == "Windows":
            exts = [".pyd", ".dll"]
        elif system == "Darwin":
            exts = [".dylib", ".so"]
        else:
            exts = [".so"]
        for ext in exts:
            for f in release_dir.iterdir():
                if f.is_file() and f.suffix == ext:
                    return str(f)

    return ""

def verify_build(project_dir: Path, *,
                 run_cargo_test: bool = True) -> VerifyResult:
    """Run ``cargo test`` on the built crate to verify compilation."""
    if not run_cargo_test:
        return VerifyResult(success=True)

    try:
        result = subprocess.run(
            ["cargo", "test", "--release"],
            cwd=str(project_dir),
            capture_output=True,
            text=True,
            timeout=120,
        )

        # Parse test output
        passed = 0
        failed = 0
        m = re.search(r"(\d+) passed", result.stdout + result.stderr)
        if m:
            passed = int(m.group(1))
        m = re.search(r"(\d+) failed", result.stdout + result.stderr)
        if m:
            failed = int(m.group(1))

        return VerifyResult(
            success=result.returncode == 0,
            tests_run=passed + failed,
            tests_passed=passed,
            tests_failed=failed,
            stdout=result.stdout,
            stderr=result.stderr,
        )

    except subprocess.TimeoutExpired:
        return VerifyResult(
            success=False,
            stderr="cargo test timed out after 120 seconds",
        )
    except FileNotFoundError:
        return VerifyResult(
            success=False,
            stderr="cargo not found",
        )

def to_dict(self) -> Dict[str, Any]:
    d: Dict[str, Any] = {
        "system": self.system.to_dict(),
        "scan_duration_s": self.scan_duration_s,
        "candidates_total": self.candidates_total,
        "candidates_selected": self.candidates_selected,
        "test_gen_path": self.test_gen_path,
        "verify_test_path": self.verify_test_path,
        "cargo_project_path": self.cargo_project_path,
        "errors": self.errors,
        "phases": self.phases,
    }
    if self.compile_result:
        d["compile"] = {
            "success": self.compile_result.success,
            "target": self.compile_result.target_triple,
            "artefact": self.compile_result.artefact_path,
            "duration_s": self.compile_result.duration_s,
            "rustflags": self.compile_result.rustflags,
        }
    if self.verify_result:
        d["verify"] = {
            "success": self.verify_result.success,
            "passed": self.verify_result.tests_passed,
            "failed": self.verify_result.tests_failed,
        }
    return d

def _report(self, frac: float, label: str):
    if self._progress_cb:
        self._progress_cb(frac, label)

def find(self, x: str) -> str:
    self._parent.setdefault(x, x)
    while self._parent[x] != x:
        self._parent[x] = self._parent.get(self._parent[x], self._parent[x])
        x = self._parent[x]
    return x

def union(self, a: str, b: str):
    ra, rb = self.find(a), self.find(b)
    if ra != rb:
        self._parent[ra] = rb

def _cluster_by_root(pairs, uf, max_sim):
    """Group function-records by union-find root."""
    clusters: Dict[str, List[Tuple[FunctionRecord, float]]] = defaultdict(list)
    for f1, f2, sim in pairs:
        root = uf.find(f1.key)
        if not any(x[0].key == f1.key for x in clusters[root]):
            clusters[root].append((f1, max_sim[f1.key]))
        if not any(x[0].key == f2.key for x in clusters[root]):
            clusters[root].append((f2, max_sim[f2.key]))
    return clusters

def _collect_cluster_sims(pairs, uf):
    """Collect per-cluster pair-similarity lists."""
    cluster_pair_sims: Dict[str, List[float]] = defaultdict(list)
    for f1, f2, sim in pairs:
        cluster_pair_sims[uf.find(f1.key)].append(sim)
    return cluster_pair_sims

def __init__(self):
    self.groups: List[DuplicateGroup] = []
    self._tokens: Dict[str, Counter] = {}

def _refine_with_fuzzer(self, functions: List[FunctionRecord]):
    """Run Semantic Fuzzer on near/semantic groups to detect operational morphing."""
    fuzzer = SemanticFuzzer()
    func_map = {f.key: f for f in functions}

    for group in self.groups:
        if group.similarity_type in ("exact", "structural", "operational"):
            continue
        if len(group.functions) < 2:
            continue

        # Pick candidates (pairwise or just leader vs others)
        # For simplicity, compare first function with others if they look promising

        # Optimization: only fuzz if similarity is high enough to warrant the cost
        if group.avg_similarity < 0.6: 
            continue

        leader_key = group.functions[0]["key"]
        leader = func_map.get(leader_key)
        if not leader: continue

        # Use executable code from leader
        try:
            # Need executable objects. This is tricky since we only have FunctionRecords with string code.
            # SemanticFuzzer typically needs callable objects OR we adapt it to compile from source.
            # We'll adapt here: compile the code string into a function object.
            exec_globals = {}
            exec(leader.code, exec_globals)
            func_a = exec_globals.get(leader.name)
        except Exception as e:
            logger.debug(f"Fuzzer compilation failed for {leader.name}: {e}")
            continue

        confirmed_group = True
        for member in group.functions[1:]:
            mem = func_map.get(member["key"])
            if not mem: continue

            try:
                exec_globals_b = {}
                exec(mem.code, exec_globals_b)
                func_b = exec_globals_b.get(mem.name)

                if not func_a or not func_b:
                    confirmed_group = False
                    break

                is_equiv, _ = fuzzer.check_equivalence(func_a, func_b, iterations=20)
                if not is_equiv:
                    confirmed_group = False
                    # If not equivalent, we should arguably split the group or just leave it as 'semantic'
                    # For now, we only upgrade if ALL are equivalent? Or just mark pairwise.
                    # We'll keep it simple: if Pair(A, B) is equivalent, great.
            except Exception:
                confirmed_group = False

        if confirmed_group:
            group.similarity_type = "operational"
            group.avg_similarity = 1.0
            group.merge_suggestion = "Functions are operationally identical (Doppelgänger). Safe to merge."

def _precompute_tokens(self, functions: List[FunctionRecord]) -> None:
    """Pre-compute TF-IDF tokens for all functions (shared across stages)."""
    for func in functions:
        text = " ".join([
            func.name,
            func.docstring or "",
            " ".join(func.parameters),
            func.return_type or "",
            " ".join(func.calls_to),
            func.code or "",
        ])
        self._tokens[func.key] = _term_freq(tokenize(text))

def _stage_hash_matches(self, functions: List[FunctionRecord],
                       cross_file_only: bool, group_id: int,
                       seen_keys: Set[str]) -> int:
    """Stage 1: Exact code hash + Structural hash matching (120 lines → 55 lines)."""
    # 1a. Exact hash matches
    hash_groups: Dict[str, List[FunctionRecord]] = defaultdict(list)
    for func in functions:
        if func.name not in self._BOILERPLATE:
            hash_groups[func.code_hash].append(func)

    for code_hash, group in hash_groups.items():
        if len(group) < 2 or (cross_file_only and len({f.file_path for f in group}) < 2):
            continue
        self.groups.append(DuplicateGroup(
            group_id=group_id, similarity_type="exact", avg_similarity=1.0,
            functions=[{"key": f.key, "name": f.name, "file": f.file_path,
                       "line": f.line_start, "size": f.size_lines, "similarity": 1.0}
                      for f in group],
        ))
        seen_keys.update(f.key for f in group)
        group_id += 1

    # 1b. Structural hash matches
    struct_groups: Dict[str, List[FunctionRecord]] = defaultdict(list)
    for func in functions:
        if (func.key not in seen_keys and func.name not in self._BOILERPLATE
            and func.size_lines >= 4 and func.structure_hash):
            struct_groups[func.structure_hash].append(func)

    for s_hash, group in struct_groups.items():
        if len(group) < 2 or (cross_file_only and len({f.file_path for f in group}) < 2):
            continue
        self.groups.append(DuplicateGroup(
            group_id=group_id, similarity_type="structural", avg_similarity=1.0,
            functions=[{"key": f.key, "name": f.name, "file": f.file_path,
                       "line": f.line_start, "size": f.size_lines, "similarity": 1.0}
                      for f in group],
            merge_suggestion="Logic is identical. Rename variables to unify."
        ))
        seen_keys.update(f.key for f in group)
        group_id += 1
    return group_id

def _batch_code_similarity(self, candidates: List[Tuple[FunctionRecord, FunctionRecord, float]]) -> List[Tuple[FunctionRecord, FunctionRecord, float]]:
    """Compute similarity matrix in Rust (parallel)."""
    code_to_idx, code_list = {}, []
    for f1, f2, _ in candidates:
        for f in (f1, f2):
            if f.code not in code_to_idx:
                code_to_idx[f.code] = len(code_list)
                code_list.append(f.code)
    matrix = _rust_core.batch_code_similarity(code_list)
    return [(f1, f2, matrix[code_to_idx[f1.code]][code_to_idx[f2.code]])
            for f1, f2, _ in candidates
            if matrix[code_to_idx[f1.code]][code_to_idx[f2.code]] >= self.NEAR_DUP_THRESHOLD]

def _stage_semantic_similarity(self, functions: List[FunctionRecord],
                              cross_file_only: bool, group_id: int,
                              seen_keys: Set[str]) -> int:
    """Stage 3: Semantic similarity (80 lines → 20 lines)."""
    semantic_list = [f for f in functions if f.key not in seen_keys
                    and f.name not in self._BOILERPLATE
                    and f.size_lines >= self.SEMANTIC_MIN_LINES]

    sem_pairs = []
    for i, f1 in enumerate(semantic_list):
        for f2 in semantic_list[i + 1:]:
            if not (cross_file_only and f1.file_path == f2.file_path):
                sim = semantic_similarity(f1, f2)
                if sim >= self.SEMANTIC_THRESHOLD:
                    sem_pairs.append((f1, f2, sim))

    if sem_pairs:
        logger.info(f"Semantic stage: {len(sem_pairs)} functionally similar pairs")
        group_id = self._build_similarity_groups(sem_pairs, group_id, "semantic", seen_keys)

    return group_id

def _is_valid_group(self, group_stats: List[Any], cross_file: bool = True) -> bool:
    """Helper for legacy tests validation."""
    if len(group_stats) < 2:
        return False
    if cross_file:
        # assuming group_stats is list of dicts or objects with file_path/file
        files = set()
        for x in group_stats:
            if isinstance(x, dict):
                files.add(x.get("file"))
            else:
                files.add(x.file_path)
        return len(files) >= 2
    return True

def _func_to_dict(self, func: FunctionRecord) -> Dict[str, Any]:
    """Convert FunctionRecord to dict structure used in DuplicateGroup."""
    return {
        "key": func.key,
        "name": func.name,
        "file": func.file_path,
        "line": func.line_start,
        "size": func.size_lines,
        "signature": func.signature
    }

def __init__(self):
    self.suggestions: List[LibrarySuggestion] = []
    self._analyzed_count = 0

def _from_name_repetition(self, functions: List[FunctionRecord]) -> None:
    """Create suggestions from cross-file name repetition."""
    name_map: Dict[str, List[FunctionRecord]] = defaultdict(list)
    for f in functions:
        if not (f.name.startswith("__") and f.name.endswith("__")):
            name_map[f.name].append(f)

    covered_keys = {
        f.get("key") for s in self.suggestions for f in s.functions
    }

    for name, funcs in name_map.items():
        if len(funcs) < 2:
            continue
        files = {f.file_path for f in funcs}
        if len(files) < 2:
            continue
        if any(f.key in covered_keys for f in funcs):
            continue
        module_name = self._suggest_module_name([name])
        func_dicts = [
            {"name": f.name, "file": f.file_path, "line": f.line_start, "key": f.key}
            for f in funcs
        ]
        self.suggestions.append(LibrarySuggestion(
            module_name=module_name,
            description=f"Multiple functions named '{name}' across {len(files)} files",
            functions=func_dicts,
            unified_api=f"def {name}(...):",
            rationale="Identical naming suggests shared concept.",
        ))

def _suggest_module_name(self, func_names: List[str]) -> str:
    """Heuristic to name the module based on function names."""
    name = func_names[0].lower()
    if "parse" in name:
        return "utils"
    if "read" in name or "write" in name or "load" in name:
        return "io_helpers"
    if "validate" in name or "check" in name:
        return "validators"
    if "search" in name or "find" in name:
        return "search"
    return "shared_utils"

def summary(self) -> Dict[str, Any]:
    return {
        "total_suggestions": len(self.suggestions),
        "total_functions": self._analyzed_count,
        "modules_proposed": sorted(list(set(s.module_name for s in self.suggestions)))
    }

def __init__(self, extra_args: Optional[List[str]] = None):
    self.extra_args = extra_args or []
    self._ruff_path = shutil.which("ruff")

def available(self) -> bool:
    """Check if ruff is installed and executable."""
    return self._ruff_path is not None

def _map_severity(code: str) -> str:
    """Map Ruff rule code to X-Ray severity."""
    if code in _SEVERITY_MAP:
        return _SEVERITY_MAP[code]
    # Fallback by prefix
    prefix = code[0] if code else ""
    if prefix == "F":
        return Severity.WARNING      # F = pyflakes (likely bugs)
    if prefix == "E":
        return Severity.INFO         # E = pycodestyle (style)
    if prefix == "W":
        return Severity.INFO         # W = pycodestyle warnings
    return Severity.INFO

def print_duplicates(duplicates: List[DuplicateGroup], summary: Dict[str, Any]):
    """Print the ASCII duplicate report."""
    print(f"\n{SEP}")
    print("SIMILAR FUNCTIONS (X-Ray)")
    print(f"{SEP}")

    if not duplicates:
        print("No significant duplication found.")
        return

    for g in duplicates:
        print(f"Group {g.group_id} ({g.similarity_type}, avg sim: {g.avg_similarity:.2f})")
        for f in g.functions:
            print(f"  - {f['file']}:{f['line']} ({f['name']})")
        print("")

def _print_issues_by_severity(issues: List[SmellIssue], severity: str,
                              label: str, *, limit: int = 0):
    """Print issues of a given severity with optional limit."""
    filtered = [i for i in issues if i.severity == severity]
    if not filtered:
        return
    print(f"  {label} ({len(filtered)}):")
    show = filtered[:limit] if limit else filtered
    for s in show:
        icon = Severity.icon(s.severity)
        print(f"    {icon} {s.file_path}:{s.line} — {s.message}")
        if s.suggestion and not limit:
            print(f"       Fix: {s.suggestion}")
    if limit and len(filtered) > limit:
        print(f"    ... and {len(filtered) - limit} more")
    print("")

def _score_to_letter(score: float) -> str:
    """Map a numeric score (0-100) to a letter grade."""
    for threshold, letter in _GRADE_THRESHOLDS:
        if score >= threshold:
            return letter
    return "F"

def _calc_category_penalty(data: Dict[str, Any], key: str) -> tuple:
    """Calculate penalty and breakdown for one category.

    Returns (penalty, detail_dict) or (0, None) if the key has a
    special shape (e.g. duplicates).
    """
    for rule_key, _, weights, cap, extras in _PENALTY_RULES:
        if rule_key != key:
            continue
        if key == "duplicates":
            total_groups = data.get("total_groups", 0)
            penalty = min(total_groups * 0.1, cap)
            return penalty, {"penalty": round(penalty, 1), "groups": total_groups}
        counts = {k: data.get(k, 0) for k in weights}
        penalty = sum(counts[k] * w for k, w in weights.items())
        penalty = min(penalty, cap)
        detail: Dict[str, Any] = {"penalty": round(penalty, 1), **counts}
        for ef in extras:
            detail[ef] = data.get(ef, 0)
        return penalty, detail
    return 0, None

def _print_breakdown(breakdown: Dict[str, Any]) -> None:
    """Print the per-tool penalty table."""
    for tool, detail in breakdown.items():
        penalty = detail.get("penalty", 0)
        other = {k: v for k, v in detail.items() if k != "penalty"}
        details = ", ".join(f"{k}={v}" for k, v in other.items())
        print(f"    -{penalty:5.1f} pts  {tool:20s}  ({details})")

def build_json_report(root: Path, 
                      functions: List[FunctionRecord], 
                      classes: List[ClassRecord],
                      smells: List[SmellIssue], 
                      duplicates: List[DuplicateGroup], 
                      suggestions: List[LibrarySuggestion], 
                      scan_time: float) -> Dict[str, Any]:
    """Construct the full JSON report dictionary."""

    # Summaries
    smell_summary = {
        "total": len(smells),
        "critical": sum(1 for s in smells if s.severity == Severity.CRITICAL),
        "warning": sum(1 for s in smells if s.severity == Severity.WARNING),
        "issues": [
            {
                "file": s.file_path, "line": s.line, "name": s.name,
                "category": s.category, "severity": s.severity,
                "message": s.message, "suggestion": s.suggestion,
                "llm_analysis": s.llm_analysis, "source": s.source,
            } for s in smells
        ]
    }

    dup_summary = {
        "total_groups": len(duplicates),
        "total_functions_involved": sum(len(g.functions) for g in duplicates),
        "groups": [
            {
                "id": g.group_id, "type": g.similarity_type, 
                "avg_sim": g.avg_similarity,
                "functions": g.functions
            } for g in duplicates
        ]
    }

    lib_summary = {
        "total": len(suggestions),
        "suggestions": [
            {
                "module": s.module_name, "rationale": s.rationale,
                "api": s.unified_api, "candidates": s.functions
            } for s in suggestions
        ]
    }

    return {
        "version": __version__,
        "scan_time_seconds": scan_time,
        "root": str(root),
        "stats": {
            "total_functions": len(functions),
            "total_classes": len(classes),
            "avg_complexity": sum(f.complexity for f in functions) / len(functions) if functions else 0
        },
        "smells": smell_summary,
        "duplicates": dup_summary,
        "library_suggestions": lib_summary,
        "functions": [
            {"name": f.name, "file": f.file_path, "complexity": f.complexity, "loc": f.size_lines}
            for f in functions
        ]
    }

def _detect_purity(func: FunctionRecord) -> bool:
    """Return True if the function appears pure (no side effects)."""
    try:
        tree = ast.parse(func.code)
    except SyntaxError:
        return False

    for node in ast.walk(tree):
        # Global/nonlocal assignments
        if isinstance(node, (ast.Global, ast.Nonlocal)):
            return False
        # Calls to known impure functions
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in _IMPURE_CALLS:
                return False
            if isinstance(node.func, ast.Attribute) and node.func.attr in _IMPURE_ATTRS:
                return False
            if isinstance(node.func, ast.Attribute) and node.func.attr in _IMPURE_CALLS:
                return False
    return True

def _count_external_deps(func: FunctionRecord) -> int:
    """Count calls that look like external I/O or library dependencies."""
    count = 0
    for call in func.calls_to:
        if call in _IMPURE_CALLS or call in _IMPURE_ATTRS:
            count += 1
    return count

def score(self, functions: List[FunctionRecord],
          traces: Optional[List] = None,
          min_lines: int = 5) -> List[RustCandidate]:
    """Score and rank all functions. Returns sorted list (best first)."""
    trace_map: Dict[str, Any] = {}
    if traces:
        for t in traces:
            trace_map[t.func_name] = t

    candidates = []
    for func in functions:
        if func.size_lines < min_lines:
            continue
        candidate = self._score_one(func, trace_map.get(func.name))
        candidates.append(candidate)

    candidates.sort(key=lambda c: c.score, reverse=True)
    return candidates

def verify_golden(rust_fn: Callable, golden_path: str) -> Dict[str, Any]:
    """Run a Rust function against a golden fixture and report results.

    Returns a dict with 'passed', 'failed', 'errors', and 'details'.
    """
    data = json.loads(Path(golden_path).read_text(encoding="utf-8"))
    cases = data.get("cases", [])

    passed = 0
    failed = 0
    errors = 0
    details: List[Dict[str, Any]] = []

    for i, case in enumerate(cases):
        if case.get("error"):
            # Skip error cases — we only verify happy-path parity
            continue
        try:
            # Reconstruct args from repr (best-effort via literal_eval)
            args = [literal_eval(a) for a in case["args"]]
            kwargs = {k: literal_eval(v) for k, v in case.get("kwargs", {}).items()}
            result = rust_fn(*args, **kwargs)
            expected = literal_eval(case["expected_output"])

            if result == expected:
                passed += 1
            else:
                failed += 1
                details.append({
                    "case": i,
                    "status": "MISMATCH",
                    "expected": case["expected_output"],
                    "actual": repr(result),
                })
        except Exception as exc:
            errors += 1
            details.append({
                "case": i,
                "status": "ERROR",
                "error": str(exc),
            })

    return {
        "golden_file": golden_path,
        "total": len(cases),
        "passed": passed,
        "failed": failed,
        "errors": errors,
        "details": details,
    }

def available(self) -> bool:
    """Check if bandit is installed and executable."""
    return self._bandit_path is not None

def _safe_execute(self, func: Callable, kwargs: Dict[str, Any]) -> Tuple[Any, Optional[Exception]]:
    """Run function and capture result or exception."""
    try:
        return func(**kwargs), None
    except Exception as e:
        return None, e

def _classify_name(name: str) -> str:
    """Classify a NAME token as keyword, builtin, or generic identifier."""
    if keyword.iskeyword(name) or keyword.issoftkeyword(name):
        return name
    if name in _BUILTIN_NAMES:
        return name
    return 'ID'

def _classify_token(tok) -> str | None:
    """Map a single token to its normalized form, or None to skip."""
    if tok.type == _tokenize_mod.NAME:
        return _classify_name(tok.string)
    if tok.type in _TOKEN_TYPE_MAP:
        return _TOKEN_TYPE_MAP[tok.type]
    if tok.type in _PASSTHROUGH_TYPES:
        return tok.string
    return None

def _normalized_token_stream(code: str) -> List[str]:
    """Tokenize Python code, normalizing identifiers and literals."""
    tokens: List[str] = []
    try:
        for tok in _tokenize_mod.generate_tokens(io.StringIO(code).readline):
            normalized = _classify_token(tok)
            if normalized is not None:
                tokens.append(normalized)
    except _tokenize_mod.TokenError:
        pass
    return tokens

def _ngram_fingerprints(tokens: List[str], n: int = 5, w: int = 4) -> frozenset:
    """Winnowed n-gram fingerprinting (MOSS algorithm)."""
    if len(tokens) < n:
        return frozenset()
    hashes: List[int] = []
    for i in range(len(tokens) - n + 1):
        gram = ' '.join(tokens[i:i + n])
        hashes.append(int(hashlib.sha256(gram.encode()).hexdigest()[:8], 16))
    if len(hashes) < w:
        return frozenset(hashes)
    fingerprints: set = set()
    for i in range(len(hashes) - w + 1):
        fingerprints.add(min(hashes[i:i + w]))
    return frozenset(fingerprints)

def _token_ngram_similarity(code_a: str, code_b: str) -> float:
    """Jaccard similarity of winnowed n-gram fingerprints."""
    fp_a = _ngram_fingerprints(_normalized_token_stream(code_a))
    fp_b = _ngram_fingerprints(_normalized_token_stream(code_b))
    if not fp_a or not fp_b:
        return 0.0
    return len(fp_a & fp_b) / len(fp_a | fp_b)

def _ast_node_histogram(code: str) -> Counter:
    """Count occurrences of each AST node type."""
    try:
        tree = ast.parse(code)
    except SyntaxError:
        return Counter()
    return Counter(type(node).__name__ for node in ast.walk(tree))

def _ast_histogram_similarity(code_a: str, code_b: str) -> float:
    """Cosine similarity of AST node-type histograms."""
    ha = _ast_node_histogram(code_a)
    hb = _ast_node_histogram(code_b)
    return cosine_similarity(ha, hb)

def code_similarity(code_a: str, code_b: str) -> float:
    """
    Structural similarity between two code blocks (0–1).
    Uses Python implementation by default, falls back to Rust if configured.
    """
    if _HAS_RUST:
        return _rust_core.code_similarity(code_a, code_b)
    if not code_a or not code_b:
        return 0.0
    if code_a == code_b:
        return 1.0
    tok_sim = _token_ngram_similarity(code_a, code_b)
    ast_sim = _ast_histogram_similarity(code_a, code_b)
    return min(0.35 * tok_sim + 0.65 * ast_sim, 1.0)

def name_similarity(name_a: str, name_b: str) -> float:
    """Semantic similarity between two function names (0–1)."""
    ta = set(tokenize(name_a))
    tb = set(tokenize(name_b))
    if not ta or not tb:
        return 0.0
    return len(ta & tb) / len(ta | tb)

def callgraph_overlap(func_a, func_b) -> float:
    """Jaccard overlap of functions each function calls."""
    ca = set(func_a.calls_to)
    cb = set(func_b.calls_to)
    if not ca or not cb:
        return 0.0
    return len(ca & cb) / len(ca | cb)

def __init__(self):
    self.nodes: List[Dict[str, Any]] = []
    self.edges: List[Dict[str, Any]] = []

def _build_smell_map(smells: List[SmellIssue]) -> Dict[str, List[SmellIssue]]:
    """Map ``file::name`` keys to their associated SmellIssue lists."""
    smell_map: Dict[str, List[SmellIssue]] = {}
    for s in smells:
        if not s.name:
            continue
        p = Path(s.file_path)
        parent = str(p.parent).replace("\\", "/")
        stem = p.stem
        k = f"{stem}::{s.name}" if parent == "." else f"{parent}/{stem}::{s.name}"
        smell_map.setdefault(k, []).append(s)
    return smell_map

def _make_node(f: FunctionRecord,
               f_smells: List[SmellIssue]) -> Dict[str, Any]:
    """Create a single graph node dict for *f*."""
    critical_count = sum(1 for s in f_smells if s.severity == Severity.CRITICAL)
    warning_count = sum(1 for s in f_smells if s.severity == Severity.WARNING)

    if critical_count > 0:
        color, health = "#e74c3c", "critical"
    elif warning_count > 0:
        color, health = "#f39c12", "warning"
    else:
        color, health = "#2ecc71", "healthy"

    tooltip = f"<b>{f.name}</b><br>{f.file_path}:{f.line_start}<br>"
    if f_smells:
        tooltip += "<br><b>Issues:</b><br>"
        for s in f_smells:
            icon = Severity.icon(s.severity)
            tooltip += f"{icon} {s.category}: {s.message}<br>"

    return {
        "id": f.key, "label": f.name, "title": tooltip,
        "color": color, "health": health,
        "size": f.size_lines,
        "group": str(Path(f.file_path).parent),
    }

def _make_edges(duplicates: List[DuplicateGroup]) -> List[Dict[str, Any]]:
    """Generate pairwise edge dicts from DuplicateGroups."""
    edges: List[Dict[str, Any]] = []
    for group in duplicates:
        funcs = group.functions
        if len(funcs) < 2:
            continue
        for i in range(len(funcs)):
            for j in range(i + 1, len(funcs)):
                edges.append({
                    "from": funcs[i]["key"], "to": funcs[j]["key"],
                    "value": group.avg_similarity,
                    "title": f"{group.similarity_type} duplicate ({group.avg_similarity:.2f})",
                })
    return edges

