def compute_complexity(node: ast.AST) -> int:
    """
    Approximate cyclomatic complexity of an AST node.

    Counts: If, For, While, Try, ExceptHandler, BoolOp, Assert, comprehension.
    """
    return sum(
        1 for c in ast.walk(node)
        if isinstance(c, (ast.If, ast.For, ast.While, ast.Try,
                          ast.ExceptHandler, ast.BoolOp, ast.Assert,
                          ast.comprehension))
    )

def available(self) -> bool:
    """Check if the LLM server is reachable."""
    if getattr(self, '_force_unavailable', False):
        return False
    try:
        # Simple health check or models listing
        req = urllib.request.Request(f"{self.base_url}/models", method='GET')
        with urllib.request.urlopen(req, timeout=2) as response:
            return response.status == 200
    except Exception:
        return False

def query_sync(self, prompt: str, **kwargs) -> str:
    """Synchronous query wrapper. Raises RuntimeError if LLM is not available."""
    if not self.available:
        raise RuntimeError("LLM not available")
    return self.completion(prompt, **kwargs)

def completion(self, prompt: str, system_prompt: str = "") -> str:
    """Get a completion from the LLM."""
    url = f"{self.base_url}/chat/completions"
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {self.api_key}",
    }
    messages = []
    if system_prompt:
        messages.append({"role": "system", "content": system_prompt})
    messages.append({"role": "user", "content": prompt})

    data = {
        "model": self.model,
        "messages": messages,
        "temperature": LLM_CONFIG["temperature"],
        "max_tokens": LLM_CONFIG["max_tokens"],
    }

    for attempt in range(1, 4):
        result = self._attempt_request(url, data, headers, attempt)
        if result is not None:
            return result
    return ""

def _attempt_request(self, url: str, data: dict,
                     headers: dict, attempt: int) -> Optional[str]:
    """Execute a single LLM request attempt, returning text or *None* to retry."""
    try:
        req = urllib.request.Request(
            url, data=json.dumps(data).encode("utf-8"),
            headers=headers, method="POST",
        )
        with urllib.request.urlopen(req, timeout=LLM_CONFIG["timeout"]) as response:
            if response.status == 200:
                result = json.loads(response.read().decode("utf-8"))
                return result["choices"][0]["message"]["content"]
            logger.error(f"LLM API Error: {response.status}")
            return ""
    except urllib.error.HTTPError as e:
        if e.code in (429, 500, 502, 503, 504) and attempt < 3:
            self._backoff(attempt, f"LLM Error {e.code}")
            return None
        logger.error(f"LLM API HTTP Error: {e.code} - {e.reason}")
        return ""
    except urllib.error.URLError as e:
        if attempt < 3:
            self._backoff(attempt, f"LLM Connection Failed: {e}")
            return None
        logger.error(f"LLM Connection Failed after retries: {e}")
        return ""
    except Exception as e:
        logger.error(f"LLM Helper Unexpected Error: {e}")
        return ""

def _parse_json_response(self, response: str) -> Any:
    """Strip markdown fences and parse JSON from an LLM response."""
    response = response.strip()
    if response.startswith("```json"):
        response = response[7:]
    if response.startswith("```"):
        response = response[3:]
    if response.endswith("```"):
        response = response[:-3]

    try:
        return json.loads(response)
    except json.JSONDecodeError:
        logger.error(f"Failed to parse JSON from LLM: {response[:100]}...")
        return None

