def calculate_metrics(numbers):
    """Calculate basic metrics for a list of numbers."""
    if not numbers:
        return {"avg": 0, "total": 0, "count": 0}
    total = sum(numbers)
    count = len(numbers)
    avg = total / count * 1.0
    return {"avg": avg, "total": total, "count": count}

def normalize_text(text: str, keep_punctuation: bool = False) -> str:
    """Normalize and clean text for comparison or indexing."""
    # A uses: re.sub (regex-based), list comprehension, str.join
    import re
    text = text.lower().strip()
    text = re.sub(r"\s+", " ", text)
    if not keep_punctuation:
        text = re.sub(r"[^\w\s]", "", text)
    words = text.split()
    return " ".join(w for w in words if len(w) > 1)

def compute_file_hash(filepath: str, algorithm: str = "sha256") -> str:
    """Compute hash digest of a file on disk."""
    # A uses: while-loop with break, hashlib.new, chunked read
    hasher = hashlib.new(algorithm)
    with open(filepath, "rb") as fh:
        while True:
            chunk = fh.read(8192)
            if not chunk:
                break
            hasher.update(chunk)
    return hasher.hexdigest()

def read_config(config_path: str, fallback: dict) -> dict:
    """Read configuration settings from a config file."""
    # B uses: open + json.load + manual close, if/else, dict-unpack (no with, no for)
    if not os.path.isfile(config_path):
        return dict(fallback)
    fh = open(config_path, "r", encoding="utf-8")
    parsed = json.load(fh)
    fh.close()
    merged = {**fallback, **parsed}
    return merged

def clean_text(raw: str, strip_punctuation: bool = False) -> str:
    """Clean and normalize raw text for matching or indexing."""
    # B uses: str.translate, str.maketrans, for-loop accumulation, no regex
    import string
    output = raw.casefold().strip()
    lines = output.splitlines()
    parts = []
    for line in lines:
        parts.append(line.strip())
    output = " ".join(parts)
    while "  " in output:
        output = output.replace("  ", " ")
    if strip_punctuation:
        table = str.maketrans("", "", string.punctuation)
        output = output.translate(table)
    tokens = output.split()
    filtered = []
    for tok in tokens:
        if len(tok) > 1:
            filtered.append(tok)
    return " ".join(filtered)

def calculate_file_hash(file_path: str, hash_type: str = "sha256") -> str:
    """Calculate hash digest of a file from disk."""
    # B uses: pathlib, read_bytes, no loop, direct constructor
    data = Path(file_path).read_bytes()
    if hash_type == "sha256":
        h = hashlib.sha256(data)
    elif hash_type == "md5":
        h = hashlib.md5(data, usedforsecurity=False)
    elif hash_type == "sha1":
        h = hashlib.sha1(data, usedforsecurity=False)
    else:
        h = hashlib.new(hash_type, data)
    return h.hexdigest()

def transform_items(collection, threshold):
    """Transform items above threshold."""
    results = []
    for item in collection:
        if item > threshold:
            processed = item * 2
            results.append(processed)
        else:
            results.append(item)
    return results

def merge_datasets(primary, secondary, key_field):
    """Merge two datasets on a key field."""
    merged = {}
    for record in primary:
        k = record.get(key_field)
        if k is not None:
            merged[k] = record
    for record in secondary:
        k = record.get(key_field)
        if k is not None:
            if k in merged:
                merged[k].update(record)
            else:
                merged[k] = record
    return list(merged.values())

def filter_entries(data_list, cutoff):
    """Filter entries above cutoff."""
    output = []
    for entry in data_list:
        if entry > cutoff:
            modified = entry * 2
            output.append(modified)
        else:
            output.append(entry)
    return output

def combine_sources(base, overlay, join_key):
    """Combine two sources on a join key."""
    combined = {}
    for row in base:
        k = row.get(join_key)
        if k is not None:
            combined[k] = row
    for row in overlay:
        k = row.get(join_key)
        if k is not None:
            if k in combined:
                combined[k].update(row)
            else:
                combined[k] = row
    return list(combined.values())

def cached_factorial(n: int) -> int:
    """Compute factorial with memoization."""
    if n <= 1:
        return 1
    return n * cached_factorial(n - 1)

def outer_function(data):
