def retry_operation(callable_fn, max_retries=3, delay=1.0):
    """Retry a callable up to max_retries times with delay."""
    import time
    last_error = None
    for i in range(max_retries):
        try:
            return callable_fn()
        except Exception as exc:
            last_error = exc
            time.sleep(delay)
    raise last_error

