    rust_fn = getattr(xray_rustified, "_map_severity", None)
    if rust_fn is None:
        pytest.skip("function not in Rust module")
    for case in goldens:
        if case.get('error'):
            continue  # skip error cases
        kwargs = case['input']
        expected = case['output']
        try:
            result = repr(rust_fn(**kwargs))
        except Exception as e:
            pytest.fail(f"Rust raised {e} for input {kwargs}")
        assert result == expected, (
            f"Mismatch: Rust={result} vs Python={expected} for input={kwargs}")

def extract_entities(self, document: Document) -> List[Entity]:
    """Extract entities from document using regex patterns"""
    entities = []

    # Pattern: "Name is [value]" or "Name: [value]"
    patterns = {
        'person': r'(?:Mayor|Manager|Director|CEO|President|Head)\s+(?:is\s+)?([A-Z][a-z]+\s+[A-Z][a-z]+)',
        'location': r'(?:City|Town|Place|Located in)\s+(?:is\s+)?([A-Z][a-z]+)',
        'organization': r'(?:Company|Organization|Department)\s+(?:is\s+)?([A-Z][a-z\s]+)',
        'date': r'\d{4}[-/]\d{2}[-/]\d{2}',
        'number': r'(?:Population|Members|Count|Total)[\s:]+(\d+(?:,\d{3})*)',
    }

    for entity_type, pattern in patterns.items():
        matches = re.findall(pattern, document.content, re.IGNORECASE)
        for match in matches:
            if isinstance(match, tuple):
                value = match[0] if match else ""
            else:
                value = match

            if value and len(value) > 2:
                entities.append(Entity(
                    name=value,
                    type=entity_type,
                    values=[value],
                    sources=[document.url],
                    confidence=0.7
                ))

    return entities

def add_document(self, document: Document):
    """Add document and detect conflicts"""
    entities = self.extract_entities(document)

    for entity in entities:
        key = f"{entity.name}_{entity.type}"

        if key in self.entities:
            # Entity exists - check for conflicts
            existing = self.entities[key]

            # If different values, create conflict
            if entity.values[0] not in existing.values:
                self._create_conflict(existing, entity, document)
            else:
                # Same value, add source
                existing.sources.extend(entity.sources)
                existing.confidence = min(1.0, existing.confidence + 0.1)
        else:
            # New entity
            self.entities[key] = entity

def _create_conflict(self, existing: Entity, new: Entity, doc: Document):
    """Create a conflict record"""

    # Calculate severity based on difference
    if existing.type == 'person':
        severity = 'high'  # Person conflicts are important
    elif existing.type in ['date', 'number']:
        severity = 'medium'
    else:
        severity = 'low'

    # Create conflict ID
    conflict_id = hashlib.md5(
        f"{existing.name}_{existing.type}".encode()
    ).hexdigest()[:8]

    conflict = Conflict(
        entity_name=existing.name,
        entity_type=existing.type,
        versions=[
            {
                'value': v,
                'source_url': s,
                'source_title': existing.name,
                'confidence': existing.confidence,
                'found_count': len(existing.sources)
            }
            for v, s in zip(existing.values, existing.sources)
        ] + [{
            'value': new.values[0],
            'source_url': doc.url,
            'source_title': doc.title,
            'confidence': new.confidence,
            'found_count': 1
        }],
        conflict_id=conflict_id,
        severity=severity,
        status='pending'
    )

    self.conflicts.append(conflict)

def get_conflicts(self, severity: Optional[str] = None) -> List[Conflict]:
    """Get conflicts, optionally filtered by severity"""
    if severity:
        return [c for c in self.conflicts if c.severity == severity]
    return self.conflicts

def resolve_conflict(self, conflict_id: str, chosen_value: str, 
                    user_notes: str = "") -> bool:
    """Resolve a conflict by choosing a value"""
    for conflict in self.conflicts:
        if conflict.conflict_id == conflict_id:
            conflict.status = 'resolved'

            # Record resolution
            self.resolution_history.append({
                'conflict_id': conflict_id,
                'entity': conflict.entity_name,
                'chosen_value': chosen_value,
                'timestamp': datetime.now().isoformat(),
                'notes': user_notes
            })

            return True
    return False

def get_stats(self) -> Dict:
    """Get conflict statistics"""
    return {
        'total_entities': len(self.entities),
        'total_conflicts': len(self.conflicts),
        'conflicts_by_severity': {
            'critical': len([c for c in self.conflicts if c.severity == 'critical']),
            'high': len([c for c in self.conflicts if c.severity == 'high']),
            'medium': len([c for c in self.conflicts if c.severity == 'medium']),
            'low': len([c for c in self.conflicts if c.severity == 'low']),
        },
        'conflicts_by_status': {
            'pending': len([c for c in self.conflicts if c.status == 'pending']),
            'resolved': len([c for c in self.conflicts if c.status == 'resolved']),
            'ignored': len([c for c in self.conflicts if c.status == 'ignored']),
        },
        'resolutions_applied': len(self.resolution_history)
    }

def __init__(self, detector: ConflictDetector):
    self.detector = detector
    self.current_conflict_idx = 0

def get_user_choice(self, conflict: Conflict) -> Tuple[str, str]:
    """Get user choice for conflict resolution"""
    print(self.display_conflict(conflict))

    print(f"\nChoose the correct version (1-{len(conflict.versions)}):")
    while True:
        try:
            choice_idx = int(input("➤ Your choice: ")) - 1
            if 0 <= choice_idx < len(conflict.versions):
                chosen_value = conflict.versions[choice_idx]['value']
                notes = input("\nNotes (optional): ")
                return chosen_value, notes
            else:
                print(f"Please enter 1-{len(conflict.versions)}")
        except ValueError:
            print("Please enter a valid number")

def update_from_resolutions(self, resolutions: List[Dict]):
    """Update KB from user resolutions"""
    for resolution in resolutions:
        entity = resolution['entity']
        value = resolution['chosen']
        self.kb[entity] = {
            'value': value,
            'updated_at': datetime.now().isoformat(),
            'notes': resolution.get('notes', ''),
            'user_approved': True
        }

    return len(resolutions)

def export_kb(self) -> Dict:
    """Export current knowledge base"""
    return self.kb

def get_stats(self) -> Dict:
    """Get KB statistics"""
    return {
        'total_entries': len(self.kb),
        'user_approved': len([e for e in self.kb.values() 
                              if e.get('user_approved')]),
        'last_updated': max([e['updated_at'] for e in self.kb.values()],
                           default='Never')
    }

def _process_conflicts_medium(self, conflicts: List[Dict]) -> int:
    """Process medium conflicts - will crash on missing fields"""
    resolved = 0

    for conflict in conflicts:
        try:
            # This will crash if 'value' is missing
            versions = conflict['versions']
            for v in versions:
                if 'value' in v:  # Safe access
                    resolved += 1
                    break

        except KeyError:
            raise

    return resolved

def _generate_hard_conflicts(self, count: int) -> List[Dict]:
    """Generate hard difficulty conflicts with nested data"""
    conflicts = []

    for i in range(count // 3):
        conflict = {
            'type': random.choice(['person', 'location', 'organization']),
            'entity': f'Entity_{i}',
            'metadata': {
                'priority': random.randint(1, 5),  # Type: int
                'source_urls': [f'url_{j}' for j in range(random.randint(1, 3))],
                'nested': {
                    'confidence': random.random(),
                    'tags': ['important', 'verified'],
                    'timestamp': datetime.now().isoformat()
                }
            },
            'versions': [],
            'processed': False
        }

        # Add versions with encoding and type issues
        versions = [
            {'value': 'Normal Name', 'count': 5},
            {'value': 'François Müller', 'count': 'three'},  # Type mismatch!
            {'value': '名前テキスト', 'count': 2},  # Unicode
            {'value': 123, 'count': 1},  # Wrong type entirely!
        ]

        conflict['versions'] = random.sample(versions, min(3, len(versions)))
        conflicts.append(conflict)

    return conflicts

def _process_conflicts_hard(self, conflicts: List[Dict]) -> int:
    """Process hard conflicts with nested access"""
    resolved = 0

    for conflict in conflicts:
        try:
            # Access nested structure
            priority = conflict['metadata']['priority']

            # Type checking
            if not isinstance(priority, int):
                raise TypeError(f"Priority must be int, got {type(priority)}")

            # Process versions with type safety
            for version in conflict['versions']:
                value = version.get('value', '')
                count = version.get('count', 0)

                # This will crash if count is not int
                if isinstance(count, str):
                    raise TypeError(f"Count must be int, got string: {count}")

                if isinstance(value, str):
                    resolved += 1

        except (TypeError, KeyError):
            raise

    return resolved

def _generate_extreme_conflicts(self, count: int) -> List[Dict]:
    """Generate extreme difficulty conflicts"""
    conflicts = []

    for i in range(count):
        # Create deeply nested structure
        conflict = {
            'id': f'conflict_{i}',
            'type': 'complex',
            'depth': random.randint(1, 10),
            'data': self._create_nested_structure(random.randint(3, 8)),
            'versions': self._create_circular_references(),
            'metadata': {
                'source_count': random.randint(5, 20),
                'conflict_chain': [f'c_{j}' for j in range(random.randint(1, 5))],
            }
        }
        conflicts.append(conflict)

    return conflicts

def _create_nested_structure(self, depth: int) -> Dict:
    """Create deeply nested dictionary structure"""
    if depth == 0:
        return {'value': f'leaf_{random.randint(1, 1000)}'}
    else:
        return {'nested': self._create_nested_structure(depth - 1)}

def _create_circular_references(self) -> List[Dict]:
    """Create versions with potential circular references"""
    versions = []
    for i in range(random.randint(2, 5)):
        v = {
            'id': i,
            'value': f'Version {i}',
            'parent': None,
            'children': []
        }
        # Simulate potential circular reference
        if i > 0:
            v['parent'] = i - 1
        versions.append(v)

    return versions

def _process_conflicts_extreme(self, conflicts: List[Dict]) -> int:
    """Process extreme conflicts with deep recursion"""
    resolved = 0
    recursion_limit = sys.getrecursionlimit()

    try:
        for conflict in conflicts:
            # Deep recursion on nested structure
            depth = self._calculate_depth(conflict['data'], 0)

            if depth > recursion_limit / 2:
                # Risk of stack overflow
                raise RecursionError(f"Nesting depth {depth} too deep")

            # Process versions
            for v in conflict['versions']:
                if v.get('value'):
                    resolved += 1

    except RecursionError:
        raise

    return resolved

def _calculate_depth(self, obj: Dict, current_depth: int) -> int:
    """Recursively calculate nesting depth"""
    if current_depth > 100:  # Safety limit
        raise RecursionError("Maximum recursion depth exceeded")

    if isinstance(obj, dict):
        if 'nested' in obj:
            return self._calculate_depth(obj['nested'], current_depth + 1)
        else:
            return current_depth
    return current_depth

def _record_crash(self, level_name: str, error: Exception):
    """Record crash information"""
    self.crashes.append({
        'level': level_name,
        'error_type': type(error).__name__,
        'error_msg': str(error),
        'traceback': traceback.format_exc(),
        'timestamp': datetime.now().isoformat()
    })

def _apply_fix(self, level_name: str, error: Exception):
    """Apply fixes based on error type"""
    error_type = type(error).__name__

    if error_type == 'KeyError':
        fix = {
            'issue': 'Missing required field',
            'cause': 'Incomplete document records',
            'fix': 'Add field validation before processing',
            'code': 'if field in record: process(record[field])'
        }
    elif error_type == 'TypeError':
        fix = {
            'issue': 'Type mismatch',
            'cause': 'Data format inconsistencies',
            'fix': 'Add type checking for all values',
            'code': 'if isinstance(value, expected_type): process(value)'
        }
    elif error_type == 'RecursionError':
        fix = {
            'issue': 'Stack overflow',
            'cause': 'Deep nesting or circular references',
            'fix': 'Implement iterative processing or set recursion limit',
            'code': 'Use stack-based approach instead of recursion'
        }
    else:
        fix = {
            'issue': 'Unknown error',
            'cause': error_type,
            'fix': 'Review error details',
            'code': str(error)
        }

    self.fixes_applied.append({
        'level': level_name,
        'error': error_type,
        'fix': fix,
        'applied_at': datetime.now().isoformat()
    })

    print("\n  [FIX APPLIED]:")
    print(f"     Issue: {fix['issue']}")
    print(f"     Cause: {fix['cause']}")
    print(f"     Solution: {fix['fix']}")

def _precompute_tokens(self, functions: List[FunctionRecord]) -> None:
    """Pre-compute TF-IDF tokens for all functions."""
    for func in functions:
        text = " ".join([
            func.name,
            func.docstring or "",
            " ".join(func.parameters),
            func.return_type or "",
            " ".join(func.calls_to),
            func.code or "",
        ])
        self._tokens[func.key] = _term_freq(tokenize(text))

def _stage_hash_matches(self, functions: List[FunctionRecord],
                        cross_file_only: bool, group_id: int,
                        seen_keys: Set[str]) -> int:
    """Stage 1: Exact code hash + Structural hash matching."""

    # 1a. Exact hash matches
    hash_groups: Dict[str, List[FunctionRecord]] = defaultdict(list)
    for func in functions:
        if func.name not in self._BOILERPLATE:
            hash_groups[func.code_hash].append(func)

    for code_hash, group in hash_groups.items():
        if len(group) < 2:
            continue
        if cross_file_only and len({f.file_path for f in group}) < 2:
            continue

        self.groups.append(DuplicateGroup(
            group_id=group_id,
            similarity_type="exact",
            avg_similarity=1.0,
            functions=[
                {"key": f.key, "name": f.name, "file": f.file_path,
                 "line": f.line_start, "size": f.size_lines,
                 "similarity": 1.0}
                for f in group
            ],
        ))
        seen_keys.update(f.key for f in group)
        group_id += 1

    # 1b. Structural hash matches (same AST, different variable names)
    struct_groups: Dict[str, List[FunctionRecord]] = defaultdict(list)
    for func in functions:
        if (func.key not in seen_keys and 
            func.name not in self._BOILERPLATE and 
            func.size_lines >= 4 and 
            func.structure_hash):
            struct_groups[func.structure_hash].append(func)

    for s_hash, group in struct_groups.items():
        if len(group) < 2:
            continue
        if cross_file_only and len({f.file_path for f in group}) < 2:
            continue

        self.groups.append(DuplicateGroup(
            group_id=group_id,
            similarity_type="structural",
            avg_similarity=1.0,
            functions=[
                {"key": f.key, "name": f.name, "file": f.file_path,
                 "line": f.line_start, "size": f.size_lines,
                 "similarity": 1.0}
                for f in group
            ],
            merge_suggestion="Logic is identical. Rename variables to unify."
        ))
        seen_keys.update(f.key for f in group)
        group_id += 1

    return group_id

def _batch_code_similarity(self, candidates: List[Tuple[FunctionRecord, FunctionRecord, float]]) -> List[Tuple[FunctionRecord, FunctionRecord, float]]:
    """Compute similarity matrix in Rust (parallel)."""
    code_to_idx: Dict[str, int] = {}
    code_list: List[str] = []

    for f1, f2, _ in candidates:
        for f in (f1, f2):
            if f.code not in code_to_idx:
                code_to_idx[f.code] = len(code_list)
                code_list.append(f.code)

    matrix = _rust_core.batch_code_similarity(code_list)

    pairs = []
    for f1, f2, _ in candidates:
        sim = matrix[code_to_idx[f1.code]][code_to_idx[f2.code]]
        if sim >= self.NEAR_DUP_THRESHOLD:
            pairs.append((f1, f2, sim))

    return pairs
